import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const AGENT_ID = 'YOUR_AGENT_ID';
const ALIAS_ID = 'YOUR_AGENT_ALIAS_ID';

async function invokeCodingAgent(sessionId: string, query: string) {
  const command = new InvokeAgentCommand({
    agentId: AGENT_ID,
    agentAliasId: ALIAS_ID,
    sessionId: sessionId,
    inputText: query,
    enableTrace: true
  });

  const response = await client.send(command);
  let completion = '';

  for await (const event of response.completion!) {
    if (event.chunk?.bytes) {
      completion += new TextDecoder().decode(event.chunk.bytes);
    }
  }

  return { sessionId, output: completion };
}

// Usage
invokeCodingAgent('debug-python-456', 'Fix the SQL injection in this query');

