import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

async function invokeAgentWithVex(agentId: string, query: string, sessionId: string) {
  const bedrockResponse = await invokeCodingAgent(agentId, query, sessionId);

  const verification = await vex.verify({
    content: bedrockResponse.output,
    context: { type: 'code', language: 'python' },
    checks: [
      'code_correctness',
      'security_vulnerabilities',
      'credential_leakage',
      'dependency_safety',
      'license_compliance'
    ],
    riskProfile: 'medium'
  });

  return {
    code: bedrockResponse.output,
    isSafe: verification.passes,
    score: verification.score,
    issues: verification.issues
  };
}

