from typing import Dict, List

class CodingSession:
    def __init__(self):
        self.state = {'files': {}, 'test_results': []}

    @vex.verify(guards=['session_consistency'])
    def process_turn(self, query: str, agent_response: Dict) -> Dict:
        # Update session state
        if 'code' in agent_response:
            self.state['files'][query] = agent_response['code']

        # Vex validates state consistency
        return {
            'response': agent_response,
            'session_state': self.state,
            'turn_count': len(self.state['test_results']) + 1
        }

